export enum Criticality {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high',
  CRITICAL = 'critical',
}

export interface CriticalityAssessment {
  /**
   * Assess the criticality of a task given its file paths and an optional context.
   * @param filePaths - Array of file paths involved in the request.
   * @param context - Optional key/value pairs containing additional context such as keywords.
   * @returns A Criticality enum value.
   */
  assess(filePaths: string[], context?: Record<string, any>): Criticality;
}

/**
 * An assessment class that uses file path heuristics and context cues.
 *   - Paths including '/security/', '/auth/', or '/database/' return CRITICAL.
 *   - Paths including '/architecture/' or '/core/' return HIGH.
 *   - Files like 'package.json' or paths including '/.env' return MEDIUM.
 *   - If context contains keywords like 'credential' or 'token', CRITICAL is returned.
 *   - Otherwise, the default is LOW.
 */
export class FilePathCriticalityAssessor implements CriticalityAssessment {
  assess(filePaths: string[], context?: Record<string, any>): Criticality {
    const criticalPaths = ['/security/', '/auth/', '/database/'];
    const highPaths = ['/architecture/', '/core/'];

    for (const path of filePaths) {
      const lowerPath = path.toLowerCase();
      if (criticalPaths.some(keyword => lowerPath.includes(keyword))) {
        return Criticality.CRITICAL;
      }
      if (highPaths.some(keyword => lowerPath.includes(keyword))) {
        return Criticality.HIGH;
      }
      if (lowerPath.endsWith('package.json') || lowerPath.includes('/.env')) {
        return Criticality.MEDIUM;
      }
    }

    if (context && Array.isArray(context.keywords)) {
      const keywords: string[] = context.keywords.map((w: string) => w.toLowerCase());
      if (keywords.includes('credential') || keywords.includes('token')) {
        return Criticality.CRITICAL;
      }
    }

    return Criticality.LOW;
  }
}
