describe('FilePathCriticalityAssessor', () => {
  const assessor = new FilePathCriticalityAssessor();

  test('should return CRITICAL for file paths containing "/security/"', () => {
    const result = assessor.assess(['/src/security/authHandler.ts']);
    expect(result).toBe(Criticality.CRITICAL);
  });

  test('should return CRITICAL for file paths containing "/auth/"', () => {
    const result = assessor.assess(['/src/controllers/auth/login.ts']);
    expect(result).toBe(Criticality.CRITICAL);
  });

  test('should return HIGH for file paths containing "/architecture/"', () => {
    const result = assessor.assess(['/architecture/main.ts']);
    expect(result).toBe(Criticality.HIGH);
  });

  test('should return HIGH for file paths containing "/core/"', () => {
    const result = assessor.assess(['/core/utils/helper.ts']);
    expect(result).toBe(Criticality.HIGH);
  });

  test('should return MEDIUM for configuration files like "package.json"', () => {
    const result = assessor.assess(['/package.json']);
    expect(result).toBe(Criticality.MEDIUM);
  });

  test('should return MEDIUM for files containing "/.env"', () => {
    const result = assessor.assess(['/config/.env']);
    expect(result).toBe(Criticality.MEDIUM);
  });

  test('should return CRITICAL if context keywords include "credential"', () => {
